```java
List<Employee> staff = Arrays.asList(
    new Employee("Aisha",  "Engineering", "Hyderabad", 95000, 5),
    new Employee("Raj",    "Sales",       "Mumbai",    72000, 3),
    new Employee("Priya",  "Engineering", "Bengaluru", 88000, 4),
    new Employee("Vikram", "Marketing",   "Hyderabad", 65000, 2),
    new Employee("Anita",  "Sales",       "Hyderabad", 78000, 6)
);

// Query 1: group by dept
Map<String, List<Employee>> byDept = staff.stream()
    .collect(Collectors.groupingBy(Employee::getDept));

byDept.forEach((dept, emps) -> 
    System.out.println(dept + ": " + emps.size() + " employees"));
```

```java
// Query 2: avg salary per dept
Map<String, Double> avgByDept = staff.stream()
    .collect(Collectors.groupingBy(
        Employee::getDept,
        Collectors.averagingDouble(Employee::getSalary)
    ));

avgByDept.forEach((dept, avg) ->
    System.out.printf("%s avg: ₹%.0f%n", dept, avg));

// Query 3: top earner name per dept
Map<String, Optional<Employee>> topByDept = staff.stream()
    .collect(Collectors.groupingBy(
        Employee::getDept,
        Collectors.maxBy(Comparator.comparingDouble(Employee::getSalary))
    ));

topByDept.forEach((dept, emp) ->
    emp.ifPresent(e -> System.out.println(dept + " top: " + e.getName())));
```

```java
// Query 4: partition by performance (salary >= 80000 = good review)
Map<Boolean, Long> reviewPartition = staff.stream()
    .collect(Collectors.partitioningBy(
        e -> e.getSalary() >= 80000,
        Collectors.counting()
    ));
System.out.println("Good review: " + reviewPartition.get(true));
System.out.println("Needs improvement: " + reviewPartition.get(false));

// Query 5: dept → 'N employees, avg ₹X'
Map<String, String> summaries = staff.stream()
    .collect(Collectors.groupingBy(
        Employee::getDept,
        Collectors.collectingAndThen(
            Collectors.toList(),
            list -> list.size() + " employees, avg ₹"
                + (int) list.stream()
                    .mapToDouble(Employee::getSalary).average().orElse(0)
        )
    ));

summaries.forEach((dept, summary) ->
    System.out.println(dept + ": " + summary));
```

worked_example.final_code:
import java.util.*;
import java.util.stream.*;

class Employee {
    private String name, dept, city;
    private double salary;
    private int yearsExp;
    Employee(String n, String d, String c, double s, int y) {
        name=n; dept=d; city=c; salary=s; yearsExp=y;
    }
    public String getName() { return name; }
    public String getDept() { return dept; }
    public double getSalary() { return salary; }
}

public class HRAnalytics {
    public static void main(String[] args) {
        List<Employee> staff = Arrays.asList(
            new Employee("Aisha",  "Engineering", "Hyderabad", 95000, 5),
            new Employee("Raj",    "Sales",       "Mumbai",    72000, 3),
            new Employee("Priya",  "Engineering", "Bengaluru", 88000, 4),
            new Employee("Vikram", "Marketing",   "Hyderabad", 65000, 2),
            new Employee("Anita",  "Sales",       "Hyderabad", 78000, 6)
        );

        System.out.println("--- Group by dept ---");
        Map<String, List<Employee>> byDept = staff.stream()
            .collect(Collectors.groupingBy(Employee::getDept));
        byDept.forEach((d, e) -> System.out.println(d + ": " + e.size()));

        System.out.println("\n--- Avg salary ---");
        staff.stream()
            .collect(Collectors.groupingBy(Employee::getDept,
                Collectors.averagingDouble(Employee::getSalary)))
            .forEach((d, avg) -> System.out.printf("%s: ₹%.0f%n", d, avg));

        System.out.println("\n--- Top earner per dept ---");
        staff.stream()
            .collect(Collectors.groupingBy(Employee::getDept,
                Collectors.maxBy(Comparator.comparingDouble(Employee::getSalary))))
            .forEach((d, e) -> e.ifPresent(emp ->
                System.out.println(d + ": " + emp.getName())));

        System.out.println("\n--- Performance partition ---");
        Map<Boolean, Long> partition = staff.stream()
            .collect(Collectors.partitioningBy(
                e -> e.getSalary() >= 80000, Collectors.counting()));
        System.out.println("Good review: " + partition.get(true));
        System.out.println("Needs improvement: " + partition.get(false));
    }
}
